n, x, pos = map(int, input().split())
if n == 1:
    print(1)
    exit(0)

MOD = 10**9 + 7
dp = [[0 for _ in range(n + 1)] for _ in range(n + 1)]
for i in range(n + 1):
    dp[i][0] = 1
for i in range(1, n + 1):
    for j in range(1, n + 1):
        dp[i][j] = (dp[i - 1][j - 1] + dp[i - 1][j]) % MOD


def solve(n, x, pos):
    if x > n:
        return 0
    if x == n:
        if pos == n - 1:
            return 1
        return 0
    res = 0
    for i in range(n - x + 1):
        res += dp[n - x][i] * dp[x - 1][i]
        res %= MOD
    return res


print(solve(n, x, pos))
